// Calculate date ranges for this week vs last week
// GSC has ~2 day data lag
const now = new Date();
const lagDays = 2;

// This week: 7 days ending 2 days ago
const thisWeekEnd = new Date(now.getTime() - lagDays * 24 * 60 * 60 * 1000);
const thisWeekStart = new Date(thisWeekEnd.getTime() - 7 * 24 * 60 * 60 * 1000);

// Last week: 7 days before this week
const lastWeekEnd = new Date(thisWeekStart.getTime());
const lastWeekStart = new Date(lastWeekEnd.getTime() - 7 * 24 * 60 * 60 * 1000);

const fmt = (d) => d.toISOString().split('T')[0];
const reportDate = fmt(now);
const weekLabel = fmt(thisWeekStart) + ' to ' + fmt(thisWeekEnd);

return [{ json: {
  thisWeekStart: fmt(thisWeekStart),
  thisWeekEnd: fmt(thisWeekEnd),
  lastWeekStart: fmt(lastWeekStart),
  lastWeekEnd: fmt(lastWeekEnd),
  reportDate,
  weekLabel
}}];

// Compile weekly SEO summary from all data sources
const calcDates = $('Calculate Date Ranges').first().json;
const thisWeekRaw = $('Fetch This Week Queries').first().json;
const lastWeekRaw = $('Fetch Last Week Queries').first().json;
const thisWeekPages = $('Fetch This Week Pages').first().json;
const gapsRaw = $('Get Content Gaps Count').first().json;
const alertsRaw = $('Get Recent Rank Drop Alerts').first().json;

// Parse GSC query data
const thisWeekQueries = (thisWeekRaw.body?.rows || thisWeekRaw.rows || []);
const lastWeekQueries = (lastWeekRaw.body?.rows || lastWeekRaw.rows || []);
const pages = (thisWeekPages.body?.rows || thisWeekPages.rows || []);

// Parse content gaps count from content-range header
const gapsHeaders = gapsRaw.headers || {};
const contentRange = gapsHeaders['content-range'] || '';
const gapCountMatch = contentRange.match(/\/(\d+)/);
const contentGapCount = gapCountMatch ? parseInt(gapCountMatch[1]) : (Array.isArray(gapsRaw.body) ? gapsRaw.body.length : 0);

// Parse rank drop alerts
const rankAlerts = Array.isArray(alertsRaw.body) ? alertsRaw.body : [];

// Build query lookup maps: query -> {clicks, impressions, position}
const thisMap = {};
for (const row of thisWeekQueries) {
  const q = row.keys?.[0] || row.query || '';
  thisMap[q] = { clicks: row.clicks || 0, impressions: row.impressions || 0, position: row.position || 0 };
}

const lastMap = {};
for (const row of lastWeekQueries) {
  const q = row.keys?.[0] || row.query || '';
  lastMap[q] = { clicks: row.clicks || 0, impressions: row.impressions || 0, position: row.position || 0 };
}

// Compute all queries from both weeks
const allQueries = new Set([...Object.keys(thisMap), ...Object.keys(lastMap)]);

// New keywords (in this week, not in last week)
const newKeywords = [];
for (const q of Object.keys(thisMap)) {
  if (!lastMap[q]) newKeywords.push({ query: q, ...thisMap[q] });
}
newKeywords.sort((a, b) => b.clicks - a.clicks);

// Lost keywords (in last week, not in this week)
const lostKeywords = [];
for (const q of Object.keys(lastMap)) {
  if (!thisMap[q]) lostKeywords.push({ query: q, ...lastMap[q] });
}
lostKeywords.sort((a, b) => b.clicks - a.clicks);

// Gainers and losers (present in both weeks)
const movers = [];
for (const q of allQueries) {
  if (thisMap[q] && lastMap[q]) {
    const clickDiff = thisMap[q].clicks - lastMap[q].clicks;
    const posDiff = lastMap[q].position - thisMap[q].position; // positive = improved
    movers.push({
      query: q,
      thisClicks: thisMap[q].clicks,
      lastClicks: lastMap[q].clicks,
      clickChange: clickDiff,
      thisPosition: Math.round(thisMap[q].position * 10) / 10,
      lastPosition: Math.round(lastMap[q].position * 10) / 10,
      positionChange: Math.round(posDiff * 10) / 10
    });
  }
}

const gainers = movers.filter(m => m.clickChange > 0).sort((a, b) => b.clickChange - a.clickChange).slice(0, 10);
const losers = movers.filter(m => m.clickChange < 0).sort((a, b) => a.clickChange - b.clickChange).slice(0, 10);

// Overall stats
const thisWeekTotalClicks = Object.values(thisMap).reduce((s, v) => s + v.clicks, 0);
const lastWeekTotalClicks = Object.values(lastMap).reduce((s, v) => s + v.clicks, 0);
const thisWeekTotalImpressions = Object.values(thisMap).reduce((s, v) => s + v.impressions, 0);
const lastWeekTotalImpressions = Object.values(lastMap).reduce((s, v) => s + v.impressions, 0);
const clickChange = thisWeekTotalClicks - lastWeekTotalClicks;
const clickChangeStr = (clickChange >= 0 ? '+' : '') + clickChange;
const impressionChange = thisWeekTotalImpressions - lastWeekTotalImpressions;
const avgPosition = thisWeekQueries.length > 0
  ? Math.round(thisWeekQueries.reduce((s, r) => s + (r.position || 0), 0) / thisWeekQueries.length * 10) / 10
  : 0;

// Top pages by clicks
const topPages = pages
  .map(p => ({ page: (p.keys?.[0] || p.page || '').replace('https://tgyardcare.com', ''), clicks: p.clicks || 0, impressions: p.impressions || 0 }))
  .sort((a, b) => b.clicks - a.clicks)
  .slice(0, 10);

return [{ json: {
  reportDate: calcDates.reportDate,
  weekLabel: calcDates.weekLabel,
  totalClicks: thisWeekTotalClicks,
  lastWeekClicks: lastWeekTotalClicks,
  clickChange,
  clickChangeStr,
  totalImpressions: thisWeekTotalImpressions,
  lastWeekImpressions: lastWeekTotalImpressions,
  impressionChange,
  avgPosition,
  totalQueries: thisWeekQueries.length,
  gainersCount: gainers.length,
  losersCount: losers.length,
  newKeywordsCount: newKeywords.length,
  lostKeywordsCount: lostKeywords.length,
  contentGapCount,
  rankAlertCount: rankAlerts.length,
  gainers,
  losers,
  newKeywords: newKeywords.slice(0, 10),
  lostKeywords: lostKeywords.slice(0, 10),
  topPages,
  rankAlerts: rankAlerts.slice(0, 5)
}}];

// Build comprehensive HTML email for weekly SEO summary
const d = $('Compile Summary').first().json;

const pct = (curr, prev) => {
  if (prev === 0) return curr > 0 ? '+100%' : '0%';
  const p = Math.round(((curr - prev) / prev) * 100);
  return (p >= 0 ? '+' : '') + p + '%';
};

const arrow = (val) => val > 0 ? '&#9650;' : val < 0 ? '&#9660;' : '&#9644;';
const color = (val) => val > 0 ? '#22c55e' : val < 0 ? '#ef4444' : '#888';

// Gainers table rows
const gainerRows = d.gainers.map(g => 
  `<tr><td style="padding:6px 10px;border-bottom:1px solid #eee;">${g.query}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${g.thisClicks}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;color:${color(g.clickChange)};">${g.clickChange > 0 ? '+' : ''}${g.clickChange}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${g.thisPosition}</td></tr>`
).join('');

// Losers table rows
const loserRows = d.losers.map(l => 
  `<tr><td style="padding:6px 10px;border-bottom:1px solid #eee;">${l.query}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${l.thisClicks}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;color:${color(l.clickChange)};">${l.clickChange > 0 ? '+' : ''}${l.clickChange}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${l.thisPosition}</td></tr>`
).join('');

// New keywords rows
const newKwRows = d.newKeywords.map(k => 
  `<tr><td style="padding:6px 10px;border-bottom:1px solid #eee;">${k.query}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${k.clicks}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${k.impressions}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${Math.round(k.position * 10) / 10}</td></tr>`
).join('');

// Lost keywords rows
const lostKwRows = d.lostKeywords.map(k => 
  `<tr><td style="padding:6px 10px;border-bottom:1px solid #eee;">${k.query}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${k.clicks}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${k.impressions}</td></tr>`
).join('');

// Top pages rows
const pageRows = d.topPages.map(p => 
  `<tr><td style="padding:6px 10px;border-bottom:1px solid #eee;word-break:break-all;">${p.page || '/'}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${p.clicks}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${p.impressions}</td></tr>`
).join('');

// Rank alerts rows
const alertRows = d.rankAlerts.map(a => {
  const ad = a.data || {};
  return `<tr><td style="padding:6px 10px;border-bottom:1px solid #eee;">${ad.query || 'N/A'}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;">${ad.previous_position || '-'}</td><td style="padding:6px 10px;border-bottom:1px solid #eee;text-align:right;color:#ef4444;">${ad.current_position || '-'}</td></tr>`;
}).join('');

const subject = `TG SEO Weekly: ${d.totalClicks} clicks (${d.clickChangeStr}), ${d.gainersCount} gainers, ${d.losersCount} losers`;

const html = `
<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;background:#fff;">
  <div style="background:#1a1a2e;color:#fff;padding:24px;border-radius:8px 8px 0 0;">
    <h1 style="margin:0 0 8px;font-size:22px;">TotalGuard SEO Weekly Report</h1>
    <p style="margin:0;opacity:0.8;font-size:14px;">${d.weekLabel}</p>
  </div>

  <!-- Overview Stats -->
  <div style="padding:20px;background:#f8f9fa;">
    <table style="width:100%;border-collapse:collapse;">
      <tr>
        <td style="padding:12px;text-align:center;">
          <div style="font-size:28px;font-weight:bold;color:#1a1a2e;">${d.totalClicks}</div>
          <div style="font-size:12px;color:#666;">Total Clicks</div>
          <div style="font-size:14px;color:${color(d.clickChange)};">${arrow(d.clickChange)} ${d.clickChangeStr} (${pct(d.totalClicks, d.lastWeekClicks)})</div>
        </td>
        <td style="padding:12px;text-align:center;">
          <div style="font-size:28px;font-weight:bold;color:#1a1a2e;">${d.totalImpressions}</div>
          <div style="font-size:12px;color:#666;">Impressions</div>
          <div style="font-size:14px;color:${color(d.impressionChange)};">${arrow(d.impressionChange)} ${d.impressionChange >= 0 ? '+' : ''}${d.impressionChange}</div>
        </td>
        <td style="padding:12px;text-align:center;">
          <div style="font-size:28px;font-weight:bold;color:#1a1a2e;">${d.avgPosition}</div>
          <div style="font-size:12px;color:#666;">Avg Position</div>
        </td>
        <td style="padding:12px;text-align:center;">
          <div style="font-size:28px;font-weight:bold;color:#1a1a2e;">${d.totalQueries}</div>
          <div style="font-size:12px;color:#666;">Tracked Queries</div>
        </td>
      </tr>
    </table>
  </div>

  <!-- Quick Stats Row -->
  <div style="padding:16px 20px;display:flex;gap:12px;flex-wrap:wrap;">
    <span style="background:#dcfce7;color:#166534;padding:4px 12px;border-radius:12px;font-size:13px;">&#9650; ${d.gainersCount} Gainers</span>
    <span style="background:#fee2e2;color:#991b1b;padding:4px 12px;border-radius:12px;font-size:13px;">&#9660; ${d.losersCount} Losers</span>
    <span style="background:#dbeafe;color:#1e40af;padding:4px 12px;border-radius:12px;font-size:13px;">&#10010; ${d.newKeywordsCount} New Keywords</span>
    <span style="background:#fef3c7;color:#92400e;padding:4px 12px;border-radius:12px;font-size:13px;">&#10006; ${d.lostKeywordsCount} Lost Keywords</span>
    <span style="background:#f3e8ff;color:#6b21a8;padding:4px 12px;border-radius:12px;font-size:13px;">&#128269; ${d.contentGapCount} Content Gaps</span>
    ${d.rankAlertCount > 0 ? '<span style="background:#fee2e2;color:#991b1b;padding:4px 12px;border-radius:12px;font-size:13px;">&#9888; ' + d.rankAlertCount + ' Rank Alerts</span>' : ''}
  </div>

  ${d.rankAlerts.length > 0 ? `
  <!-- Rank Drop Alerts -->
  <div style="padding:0 20px 16px;">
    <h2 style="font-size:16px;color:#991b1b;margin:0 0 8px;">&#9888; Rank Drop Alerts</h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px;">
      <thead><tr style="background:#fee2e2;"><th style="padding:8px 10px;text-align:left;">Query</th><th style="padding:8px 10px;text-align:right;">Previous</th><th style="padding:8px 10px;text-align:right;">Current</th></tr></thead>
      <tbody>${alertRows}</tbody>
    </table>
  </div>` : ''}

  <!-- Top Gainers -->
  ${d.gainers.length > 0 ? `
  <div style="padding:0 20px 16px;">
    <h2 style="font-size:16px;color:#166534;margin:0 0 8px;">&#9650; Top Gainers</h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px;">
      <thead><tr style="background:#dcfce7;"><th style="padding:8px 10px;text-align:left;">Query</th><th style="padding:8px 10px;text-align:right;">Clicks</th><th style="padding:8px 10px;text-align:right;">Change</th><th style="padding:8px 10px;text-align:right;">Position</th></tr></thead>
      <tbody>${gainerRows}</tbody>
    </table>
  </div>` : ''}

  <!-- Top Losers -->
  ${d.losers.length > 0 ? `
  <div style="padding:0 20px 16px;">
    <h2 style="font-size:16px;color:#991b1b;margin:0 0 8px;">&#9660; Top Losers</h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px;">
      <thead><tr style="background:#fee2e2;"><th style="padding:8px 10px;text-align:left;">Query</th><th style="padding:8px 10px;text-align:right;">Clicks</th><th style="padding:8px 10px;text-align:right;">Change</th><th style="padding:8px 10px;text-align:right;">Position</th></tr></thead>
      <tbody>${loserRows}</tbody>
    </table>
  </div>` : ''}

  <!-- New Keywords -->
  ${d.newKeywords.length > 0 ? `
  <div style="padding:0 20px 16px;">
    <h2 style="font-size:16px;color:#1e40af;margin:0 0 8px;">&#10010; New Keywords</h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px;">
      <thead><tr style="background:#dbeafe;"><th style="padding:8px 10px;text-align:left;">Query</th><th style="padding:8px 10px;text-align:right;">Clicks</th><th style="padding:8px 10px;text-align:right;">Impressions</th><th style="padding:8px 10px;text-align:right;">Position</th></tr></thead>
      <tbody>${newKwRows}</tbody>
    </table>
  </div>` : ''}

  <!-- Lost Keywords -->
  ${d.lostKeywords.length > 0 ? `
  <div style="padding:0 20px 16px;">
    <h2 style="font-size:16px;color:#92400e;margin:0 0 8px;">&#10006; Lost Keywords</h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px;">
      <thead><tr style="background:#fef3c7;"><th style="padding:8px 10px;text-align:left;">Query</th><th style="padding:8px 10px;text-align:right;">Last Clicks</th><th style="padding:8px 10px;text-align:right;">Impressions</th></tr></thead>
      <tbody>${lostKwRows}</tbody>
    </table>
  </div>` : ''}

  <!-- Top Pages -->
  ${d.topPages.length > 0 ? `
  <div style="padding:0 20px 16px;">
    <h2 style="font-size:16px;color:#1a1a2e;margin:0 0 8px;">&#128196; Top Pages This Week</h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px;">
      <thead><tr style="background:#f1f5f9;"><th style="padding:8px 10px;text-align:left;">Page</th><th style="padding:8px 10px;text-align:right;">Clicks</th><th style="padding:8px 10px;text-align:right;">Impressions</th></tr></thead>
      <tbody>${pageRows}</tbody>
    </table>
  </div>` : ''}

  <div style="padding:16px 20px;background:#f8f9fa;border-radius:0 0 8px 8px;font-size:12px;color:#888;text-align:center;">
    TotalGuard Yard Care &mdash; Automated SEO Weekly Report (TG-102)<br>
    Generated ${d.reportDate}
  </div>
</div>`;

return [{ json: { subject, html, reportDate: d.reportDate } }];
